 1	import React, { FC, memo } from 'react';
 2	
 3	import { V1VirtualMachineCondition } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { Label, LabelGroup, Popover, PopoverPosition } from '@patternfly/react-core';
 5	
 6	export const VMStatusConditionLabel: FC<V1VirtualMachineCondition> = memo((condition) => {
 7	  return (
 8	    <Popover
 9	      aria-label="Condition Popover"
10	      bodyContent={() => <div>{condition?.message ?? condition?.reason}</div>}
11	      position={PopoverPosition.top}
12	    >
13	      <Label
14	        onClick={(e) => {
15	          e.preventDefault();
16	        }}
17	        color="grey"
18	        textMaxWidth="6ch"
19	      >
20	        {condition?.type}={condition?.status}
21	      </Label>
22	    </Popover>
23	  );
24	});
25	VMStatusConditionLabel.displayName = 'VMStatusConditionLabel';
26	
27	export const VMStatusConditionLabelList: FC<{ conditions: V1VirtualMachineCondition[] }> = memo(
28	  ({ conditions }) => {
29	    return (
30	      <LabelGroup>
31	        {conditions?.map(({ message, reason, status, type }) => (
32	          <VMStatusConditionLabel
33	            key={type}
34	            message={message}
35	            reason={reason}
36	            status={status}
37	            type={type}
38	          />
39	        ))}
40	      </LabelGroup>
41	    );
42	  },
43	);
44	VMStatusConditionLabelList.displayName = 'VMStatusConditionLabelList';

